269	  const violations = fns.flatMap((fn) => judgeFunction(relPath, fn));
270	  // Count LINES, not newline-split segments: a trailing newline (every POSIX text file) otherwise
271	  // inflates the count by one, so a legal 500-line file misreports as 501 and fails the cap.
272	  const totalLines = src.length === 0 ? 0 : src.replace(/\n$/, '').split('\n').length;
273	  if (totalLines > MAX_FILE_LINES) {
274	    violations.push({ file: relPath, line: 1, name: '(file)', kind: 'large-file', metric: totalLines, cap: MAX_FILE_LINES,
275	      message: `file is ${totalLines} lines (cap ${MAX_FILE_LINES})` });
276	  }
277	  return { violations, functions: fns.length, engine };
278	}
279	
280	function scanTree(dirs) {
281	  const violations = [];
282	  let scanned = 0;
283	  let functions = 0;
284	  for (const dir of dirs) {
285	    const absDir = path.isAbsolute(dir) ? dir : path.join(ROOT, dir);
286	    for (const abs of listJsFiles(absDir, { skipDirs: SKIP_DIRS, skipTests: true })) {
287	      scanned++;
288	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
289	      const r = scanContent(rel, fs.readFileSync(abs, 'utf8'));
290	      functions += r.functions;
291	      violations.push(...r.violations);
292	    }
293	  }
294	  return { violations, scanned, functions };
295	}
296	
297	// didThrow(fn) -> true when fn() throws. An expected-throw probe: the throw IS the signal being
298	// measured, deliberately captured, never an error to surface.
299	function didThrow(fn) {
300	  try { fn(); return false; }
301	  catch (e) { return true; /* FAIL-OPEN: the throw is the measured signal here (an expected-refusal probe), captured on purpose, not swallowed in error. */ }
302	}
303	
304	// selfTestRefusal() -> prove the heuristic fallback FAILS CLOSED: it must throw (refuse) on ANY input,
305	// clean or malformed, never return zero violations. Exercised via HEALTH_GATE_ENGINE=heuristic.
306	function selfTestRefusal() {
307	  for (const [label, src] of [['clean', 'function ok(a) { return a; }\n'], ['malformed', 'function ( { ) not js']]) {
308	    if (!didThrow(() => scanContent('selftest-' + label + '.js', src))) {
309	      return { pass: false, detail: 'heuristic fallback did NOT refuse ' + label + ' input - it must never under-report (acorn is mandatory)' };
310	    }
311	  }
312	  return { pass: true, detail: 'heuristic fallback correctly REFUSES all input (acorn mandatory; under-reporting is an unearned zero)' };
313	}
314	
315	// Self-test: prove the acorn engine can see every one of the FIVE caps this gate exists to catch,
316	// including large-file (a synthetic 501-line source, in memory). If this fails, every zero this tool
317	// has ever reported is unearned (Constitution Rule 4). Under a forced/absent heuristic, prove instead
318	// that the fallback refuses (selfTestRefusal).
319	function selfTest() {
