2	'use strict';
3	/**
4	 * SWALLOW-GATE: no failure may report success.
5	 *
6	 * A swallowed exception is how a failure reports success. The old estate was burned by this class repeatedly:
7	 * a coherence gate found 55 silent catches that an earlier regex had reported as 0. Every catch block in this
8	 * repo must do one of three things:
9	 *
10	 *   1. RETHROW            throw inside the catch body
11	 *   2. RECORD             call a recorder: _warn / warn / record* / addWarning / manifest.record /
12	 *                         logger.warn|error / console.warn|error / report* etc.
13	 *   3. JUSTIFY IN WRITING carry a "// FAIL-OPEN: <reason>" comment inside or immediately above the catch
14	 *
15	 * A bare `catch (e) {}` or `catch {}` always fails.
16	 *
17	 * Engine: AST walk via acorn when it is installed (add acorn to devDependencies to get the precise walk);
18	 * otherwise a hardened regex + brace-matching fallback that skips string and comment contexts. Both engines
19	 * fail non-zero on the same core class, and the self-test proves whichever engine is active can see it.
20	 *
21	 * Modes:
22	 *   node tools/swallow-gate/check.js                  scan the repo source tree, exit 1 on any violation
23	 *   node tools/swallow-gate/check.js --json <path>    also write findings JSON for the sweep normaliser
24	 *   node tools/swallow-gate/check.js --calibrate      scan eval/calibration-known-bad/fixtures/ and REQUIRE
25	 *                                                     that seeded violations are found. Zero found = exit 1.
26	 */
27	const fs = require('fs');
28	const path = require('path');
29	
30	const { runGateCli, ROOT } = require('../lib/gate-cli');
31	
32	const SCAN_DIRS = ['catalogue', 'evidence', 'facts', 'applicability', 'breach', 'llm', 'payload', 'mint', 'render-proof', 'tools'];
