70	// Find every catch clause with the fallback engine. Returns [{start, bodyStart, bodyEnd, line}].
71	function findCatchesRegex(src) {
72	  const out = [];
73	  const rx = /\bcatch\b\s*(\([^)]*\))?\s*\{/g;
74	  let m;
75	  while ((m = rx.exec(src)) !== null) {
76	    // Reject matches that sit inside a string or comment by rescanning context up to the match. Cheap and
77	    // exact enough: count unterminated context from the start of the line only, then a full scan when unsure.
78	    if (inStringOrComment(src, m.index)) continue;
79	    const openIdx = m.index + m[0].length - 1;
80	    const bodyEnd = matchBrace(src, openIdx);
81	    out.push({ start: m.index, bodyStart: openIdx + 1, bodyEnd: bodyEnd - 1, line: src.slice(0, m.index).split('\n').length });
82	  }
83	  return out;
84	}
