86	// True if position `idx` is inside a string, template or comment. Single forward scan.
87	function inStringOrComment(src, idx) {
88	  let i = 0;
89	  while (i < idx) {
90	    const c = src[i];
91	    const next = src[i + 1];
92	    if (c === '/' && next === '/') { const nl = src.indexOf('\n', i); if (nl === -1 || nl >= idx) return true; i = nl + 1; continue; }
93	    if (c === '/' && next === '*') { const end = src.indexOf('*/', i + 2); if (end === -1 || end + 2 > idx) return true; i = end + 2; continue; }
94	    if (c === '\'' || c === '"' || c === '`') {
95	      const q = c;
96	      i++;
97	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
98	      if (i >= idx) return true;
99	      i++;
100	      continue;
101	    }
102	    i++;
103	  }
104	  return false;
105	}
