128	  // Justification may sit inside the body or on the two lines immediately above the catch.
129	  const before = src.slice(Math.max(0, src.lastIndexOf('\n', Math.max(0, src.lastIndexOf('\n', c.start - 1) - 1))), c.start);
130	  if (JUSTIFY.test(body) || JUSTIFY.test(before)) return null;
131	  if (/\bthrow\b/.test(body)) return null;
132	  if (RECORDER.test(body)) return null;
133	  const bare = body.replace(/\/\/[^\n]*|\/\*[\s\S]*?\*\//g, '').trim() === '';
134	  return {
135	    line: c.line,
136	    kind: bare ? 'bare-swallow' : 'silent-swallow',
137	    excerpt: ('catch ' + body.trim()).replace(/\s+/g, ' ').slice(0, 120),
