177	// Self-test: prove the active engine can see the class this gate exists to catch.
178	function selfTest() {
179	  const cases = [
180	    { src: 'try { x(); } catch (e) {}', bad: 1 },                                                 // bare, bound
181	    { src: 'try { x(); } catch { }', bad: 1 },                                                    // bare, optional binding
182	    { src: 'try { x(); } catch (e) { count++; }', bad: 1 },                                       // silent: does something, records nothing
183	    { src: 'try { x(); } catch (e) { throw new Error("ctx: " + e.message); }', bad: 0 },          // rethrows
184	    { src: 'try { x(); } catch (e) { manifest.record("crawl", e); }', bad: 0 },                   // records
185	    { src: 'try { x(); } catch (e) { /* FAIL-OPEN: bonus signal only, madge is authoritative */ }', bad: 0 }, // justified
186	    { src: 'const s = "catch (e) {}";', bad: 0 },                                                 // catch inside a string is not a catch
187	  ];
188	  const results = cases.map((c) => {
189	    const got = scanContent(c.src).violations.length;
190	    return { want: c.bad, got, ok: got === c.bad, src: c.src };
191	  });
192	  const pass = results.every((r) => r.ok);
193	  return { pass, detail: results.filter((r) => !r.ok).map((r) => 'want ' + r.want + ' got ' + r.got + ' for: ' + r.src).join('; ') || 'all ' + cases.length + ' cases correct' };
194	}
195	
196	function toFindings(violations) {
197	  return violations.map((v) => ({
198	    tool: 'swallow-gate',
199	    ruleId: 'swallowed-exception:' + v.kind,
200	    file: v.file,
201	    startLine: v.line,
202	    endLine: v.line,
203	    level: 'error',
204	    message: (v.kind === 'bare-swallow' ? 'Bare empty catch: this failure reports success.' : 'Silent catch: neither rethrows, records via a recorder, nor carries a written FAIL-OPEN: justification.'),
205	    snippet: v.excerpt,
206	  }));
207	}
208	
209	function main() {
210	  const engine = acorn ? 'acorn' : 'regex-fallback';
211	  runGateCli({
212	    name: 'swallow-gate',
213	    selfTest,
214	    scan: scanTree,
215	    toFindings,
216	    scanDirs: SCAN_DIRS,
217	    summary: (r) => r.scanned + ' files, ' + r.catches + ' catch blocks, ' + r.violations.length + ' violations (engine: ' + engine + ')',
218	    calibrateSummary: (r) => r.scanned + ' fixture files, ' + r.catches + ' catches, ' + r.violations.length + ' seeded violations found',
219	    violationLine: (v) => 'SWALLOW [' + v.kind + '] ' + v.file + ':' + v.line + '  ' + v.excerpt,
220	  });
221	}
