3	/**
4	 * THE SWEEP ORCHESTRATOR. One command, the whole local fleet, one ledger.
5	 *
6	 *   node tools/sweep/run.js               full sweep -> tools/sweep/out/{ledger.json, LEDGER.md}
7	 *   node tools/sweep/run.js --calibrate   additionally run one-door + swallow-gate against
8	 *                                         eval/calibration-known-bad/fixtures/ and FAIL unless the
9	 *                                         seeded violations are found. A zero you did not earn is a lie.
10	 *
11	 * Order of battle:
12	 *   0. SELF-TESTS: one-door and swallow-gate must first prove, in memory, that they can see the class they
13	 *      exist to catch. If they cannot, the sweep aborts: every zero after a failed self-test is unearned.
14	 *   1. COLLECT: eslint lane, local analysers (reachability, jscpd, dep-cruiser), one-door, swallow-gate,
15	 *      fact-lineage. Each writes findings JSON into tools/sweep/out/sarif/. External SARIF (CodeQL, Semgrep)
16	 *      dropped into that directory by CI is ingested automatically.
17	 *   2. NORMALISE: fingerprint dedupe (SHA256 of path + rule + normalised snippet, NEVER line numbers),
18	 *      DSU cross-tool clustering, deterministic F-NNNN numbering.
19	 *   3. LEDGER: ledger.json -> LEDGER.md.
20	 *
21	 * Exit code: 0 when green. 1 when any ACT finding (>=2 tools corroborate) is open, when any gate found
22	 * violations, or when calibration failed. 2 when a self-test failed.
23	 */
24	const fs = require('fs');
25	const path = require('path');
26	const { spawnSync } = require('child_process');
27	
28	const ROOT = path.resolve(__dirname, '..', '..');
29	const OUT = path.join(ROOT, 'tools', 'sweep', 'out');
30	const SARIF = path.join(OUT, 'sarif');
31	const CALIBRATE = process.argv.includes('--calibrate');
