33	function step(title) { console.log('\n== ' + title + ' =='); }
34	
35	function runNode(script, args) {
36	  const r = spawnSync(process.execPath, [path.join(ROOT, script), ...(args || [])], { cwd: ROOT, stdio: 'inherit' });
37	  return r.status === null ? 1 : r.status;
38	}
