116	  } catch (e) {
117	    recordFinding('facts-abstain/jurisdiction-threw', domain + ': facts/jurisdiction.js threw instead of abstaining: ' + e.message);
118	  }
119	}
120	
121	function checkSector(bundle, resolveSector, domain, recordFinding) {
122	  try {
123	    const sec = resolveSector(bundle);
124	    if (sec.confidence !== 'abstain') {
125	      recordFinding('facts-abstain/sector-non-abstain', domain + ': facts/sector.js emitted sector=' + JSON.stringify(sec.value) + ' at confidence ' + sec.confidence + ' on an unreachable bundle; it must abstain');
126	    }
127	  } catch (e) {
128	    recordFinding('facts-abstain/sector-threw', domain + ': facts/sector.js threw instead of abstaining: ' + e.message);
129	  }
130	}
131	
132	function checkBundle(bundle, source, resolvers) {
133	  const R = resolvers || REAL_RESOLVERS;
134	  const findings = [];
135	  const recordFinding = (rule, message) => findings.push({ file: source, rule, message });
136	  const domain = (bundle && bundle.domain) || '(no domain)';
137	  checkIdentity(bundle, R.resolveIdentity, domain, recordFinding);
138	  checkJurisdiction(bundle, R.resolveJurisdiction, domain, recordFinding);
139	  checkSector(bundle, R.resolveSector, domain, recordFinding);
140	  return findings;
