167	// legitimately arrives ABSOLUTE (an operator naming a bundle anywhere on disk, or a test's temp
168	// fixture) and is used directly; assertSafeScanPath accepts absolute and traversal-guards a relative
169	// one, path.resolve(ROOT, abs) is a no-op for an absolute p (CR safe-path.js:43 consumer audit).
170	function resolveScanTarget(p, violations) {
171	  let abs;
172	  try {
173	    safePath.assertSafeScanPath(p, { label: 'facts-abstain scan path' });
174	    abs = path.resolve(ROOT, p);
175	  } catch (e) {
176	    recordScanError(violations, String(p), e.message);
177	    return null;
178	  }
179	  if (!fs.existsSync(abs)) {
180	    recordScanError(violations, String(p), 'path does not exist: ' + p);
181	    return null;
182	  }
183	  const isDir = fs.statSync(abs).isDirectory();
184	  const files = isDir
185	    ? fs.readdirSync(abs).filter((f) => f.endsWith('.json')).map((f) => safePath.safeJoin(abs, [f], { label: 'facts-abstain bundle filename' }))
186	    : [abs];
187	  return { files, isDir };
188	}
