190	// processBundles(bundles, rel, acc) -> run checkBundle over every bundle that LOOKS unreachable,
191	// folding its findings into acc.violations and updating the seen counters.
192	function processBundles(bundles, rel, acc) {
193	  for (const bundle of bundles) {
194	    acc.bundlesSeen++;
195	    if (!looksUnreachable(bundle)) continue;
196	    acc.unreachableSeen++;
197	    acc.violations.push(...checkBundle(bundle, rel));
198	  }
199	}
