201	// scanBundlesInFile(file, isDir, acc) -> parse one file and process its bundles. A parse failure on a
202	// file discovered while walking a MIXED DIRECTORY legitimately belongs to another gate (FAIL-OPEN,
203	// skip); a DIRECTLY named file carries no such excuse and fails closed (CR-41), recorded not swallowed.
204	function scanBundlesInFile(file, isDir, acc) {
205	  const rel = path.relative(ROOT, file).replace(/\\/g, '/');
206	  let parsed;
207	  try {
208	    parsed = JSON.parse(fs.readFileSync(file, 'utf8'));
209	  } catch (e) {
210	    if (isDir) return; // FAIL-OPEN: mixed-directory fixture belonging to another gate.
211	    recordScanError(acc.violations, rel, 'failed to read/parse as JSON: ' + e.message);
212	    return;
213	  }
214	  const bundles = bundlesIn(parsed);
215	  if (bundles.length === 0 && !isDir) {
