228	
229	  for (const p of inputs) {
230	    const target = resolveScanTarget(p, acc.violations);
231	    if (!target) continue;
232	    for (const file of target.files) scanBundlesInFile(file, target.isDir, acc);
233	  }
234	  // Terminal fail-closed check: inputs were supplied but yielded zero recognised bundles (an empty
235	  // directory, or every file skipped as malformed/unrelated). A scan that examined nothing must
236	  // never report a clean pass - same doctrine as the no-input guard above.
237	  if (inputs.length > 0 && acc.bundlesSeen === 0) {
238	    recordScanError(acc.violations, '(no bundles)', 'supplied path(s) yielded 0 recognised bundles - nothing was actually checked; an empty scan must never report a clean pass');
