293	// runSelfTestCases() -> the raw per-case results selfTest evaluates. Pulled out of selfTest as its
294	// own step (Constitution Rule 4/tools/health-gate/check.js caps: the former inline selfTest body
295	// was 61 lines).
296	function runSelfTestCases() {
