300	  const nonAbstainF = checkBundle(unreachableBundle, 'selftest', stubs.faultyNonAbstain);
301	  const throwF = checkBundle(unreachableBundle, 'selftest', stubs.faultyThrowing);
302	  const abstainingF = checkBundle(unreachableBundle, 'selftest', stubs.correctlyAbstaining);
303	
304	  const ordinaryIsNotUnreachable = looksUnreachable({
305	    domain: 'ordinary.example',
306	    corpus: { pages: [{ url: 'https://ordinary.example/', title: 'Ordinary Co', text: 'A perfectly ordinary reachable page with real content.', jsonLd: [] }] },
