309	
310	  // CR-40: blank page text but a NON-EMPTY captured footer must NOT be treated as unreachable.
311	  const footerTextIsReachable = looksUnreachable({
312	    domain: 'footer-only.example',
313	    corpus: { pages: [{ url: 'https://footer-only.example/', title: '', text: '', jsonLd: [] }], footerText: 'Footer Co Ltd, company number 12345678, registered office 1 Example Street' },
314	  }) === false;
315	
316	  // CR-41: an empty scan input must itself be a failure, never a clean pass.
317	  const emptyScanFailsClosed = scan([]).violations.some((v) => v.rule === 'facts-abstain/scan-error');
318	
319	  return { nonAbstainF, throwF, abstainingF, ordinaryIsNotUnreachable, footerTextIsReachable, emptyScanFailsClosed };
320	}
321	
322	// evaluateSelfTestCases(r) -> boolean pass; every individual expectation the original selfTest
323	// asserted, unchanged.
324	function evaluateSelfTestCases(r) {
325	  const checks = [
326	    r.nonAbstainF.some((f) => f.rule === 'facts-abstain/identity-non-abstain'),
327	    r.nonAbstainF.some((f) => f.rule === 'facts-abstain/jurisdiction-non-abstain'),
328	    r.nonAbstainF.some((f) => f.rule === 'facts-abstain/sector-non-abstain'),
329	    r.throwF.some((f) => f.rule === 'facts-abstain/identity-threw'),
330	    r.throwF.some((f) => f.rule === 'facts-abstain/jurisdiction-threw'),
331	    r.throwF.some((f) => f.rule === 'facts-abstain/sector-threw'),
332	    r.abstainingF.length === 0,
333	    r.ordinaryIsNotUnreachable,
334	    r.footerTextIsReachable,
335	    r.emptyScanFailsClosed,
