361	    summary: (r) => r.bundlesSeen + ' bundle(s) seen, ' + r.unreachableSeen + ' unreachable, ' + r.violations.length + ' violation(s)',
362	    calibrateSummary: (r) => r.bundlesSeen + ' fixture bundle(s), ' + r.unreachableSeen + ' unreachable, ' + r.violations.length + ' seeded violation(s) found',
363	    violationLine: (v) => '[' + v.rule + '] ' + v.file + ': ' + v.message,
364	  });
365	}
366	
367	if (require.main === module) main();
