'use strict';
/**
 * extract.js - the crawler's HTML -> evidence extractor. THE ONE producer of stripped visible text for
 * the corpus (caution.md C-012: sector/rule matching never runs on <script>/<style>/markup noise; the
 * evidence quote is cut from exactly this text, C-035). Pure and synchronous over an HTML string; no
 * network, no clock, no env. Every corpus page and the footer surface (C-034) come out of here.
 *
 * pageContentClass() is the C-031/C-032/C-038 guard: a login/challenge/error/SPA-shell response is
 * classified by its CONTENT, not its byte count, so a login or bot-wall page can never flip a site to
 * "reachable" or become an absence-finding surface.
 */

const NAMED_ENTITIES = {
  amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', '#39': "'",
  ndash: '-', mdash: '-', hellip: '...', copy: '(c)', reg: '(R)', trade: '(TM)',
  pound: '£', euro: '€', middot: '·', bull: '•',
};

function decodeEntities(s) {
  return String(s).replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (m, g) => {
    const key = g.toLowerCase();
    if (Object.prototype.hasOwnProperty.call(NAMED_ENTITIES, key)) return NAMED_ENTITIES[key];
    if (g[0] === '#') {
      const code = (g[1] === 'x' || g[1] === 'X') ? parseInt(g.slice(2), 16) : parseInt(g.slice(1), 10);
      if (Number.isFinite(code) && code >= 9 && code <= 0x10ffff) {
        try { return String.fromCodePoint(code); } catch (e) { return ' '; /* FAIL-OPEN: an invalid code point in hostile source HTML degrades to a space, the honest substitute; nothing is hidden. */ }
      }
    }
    return m;
  });
}

// stripHtml(html) -> visible text only. Raw-text and non-content elements are dropped whole (tolerant of
// "</script >" whitespace, caution.md html-text D-01), block closers become newlines so footer lines
// survive, remaining tags become spaces, entities are decoded, whitespace is collapsed.
function stripHtml(html) {
  let s = String(html);
  s = s.replace(/<!--[\s\S]*?-->/g, ' ');
  s = s.replace(/<(script|style|noscript|template|svg|iframe|head)\b[\s\S]*?<\/\1\s*>/gi, ' ');
  s = s.replace(/<\/(p|div|li|ul|ol|h[1-6]|tr|td|th|section|article|footer|header|nav|br)\s*>/gi, '\n');
  s = s.replace(/<br\s*\/?>/gi, '\n');
  s = s.replace(/<[^>]+>/g, ' ');
  s = decodeEntities(s);
  s = s.replace(/[ \t\r\f\v]+/g, ' ');
  s = s.replace(/ ?\n ?/g, '\n');
  s = s.replace(/\n{3,}/g, '\n\n');
  return s.trim();
}

function extractTitle(html) {
  const m = /<title[^>]*>([\s\S]*?)<\/title\s*>/i.exec(String(html));
  return m ? decodeEntities(m[1]).replace(/\s+/g, ' ').trim() : '';
}

function extractOgSiteName(html) {
  const re = /<meta\b[^>]*>/gi;
  let m;
  while ((m = re.exec(String(html))) !== null) {
    if (!/property\s*=\s*["']og:site_name["']/i.test(m[0])) continue;
    const c = /content\s*=\s*["']([^"']*)["']/i.exec(m[0]);
    if (c) return decodeEntities(c[1]).trim();
  }
  return undefined;
}

function extractJsonLd(html) {
  const out = [];
  const re = /<script\b[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script\s*>/gi;
  let m;
  while ((m = re.exec(String(html))) !== null) {
    const raw = m[1].trim();
    if (!raw) continue;
    try { out.push(JSON.parse(raw)); }
    catch (e) { /* FAIL-OPEN: invalid JSON-LD on the live site is a fact about the site; record nothing, fabricate nothing (no partial-parse guesses). */ }
  }
  return out;
}

// extractFooterText(html) -> the statutory-disclosure surface (C-034): the concatenated visible text of
// every <footer> region, else '' (the crawl caller may fall back to the page tail). Company number,
// registered office and SRA/authorisation strings live here; it is a MANDATORY detection surface.
function extractFooterText(html) {
  const out = [];
  const re = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/gi;
  let m;
  while ((m = re.exec(String(html))) !== null) { const t = stripHtml(m[1]); if (t) out.push(t); }
  return out.join('\n').trim();
}

// extractHrefs(html) -> every raw href value in the document (query strings kept, C-027). Resolution and
// same-site filtering are the crawl layer's job (via the tools/lib/safe-fetch.js parsed-host door).
function extractHrefs(html) {
  const out = [];
  const re = /href\s*=\s*["']([^"']+)["']/gi;
  let m;
  while ((m = re.exec(String(html))) !== null && out.length < 2000) out.push(decodeEntities(m[1]).trim());
  return out;
}

function buildPage(url, html) {
  const page = { url, title: extractTitle(html), text: stripHtml(html), jsonLd: extractJsonLd(html) };
  const og = extractOgSiteName(html);
  if (og !== undefined) page.ogSiteName = og;
  return page;
}

// ── content classification (C-031 / C-032 / C-038): never let a wall/login/error/shell flip reachable ──
const CHALLENGE_MARKERS = [
  'just a moment', 'attention required', 'checking your browser', 'verify you are human',
  'access denied', 'ddos protection', 'cf-challenge', 'enable javascript and cookies to continue',
  'captcha', 'request unsuccessful', 'incapsula', 'perimeterx', 'are you a robot',
];
const WALL_STATUSES = new Set([401, 403, 429, 503]);
const LOGIN_MARKERS = /(sign in|signin|log in|login|log ?into|please (?:sign|log) in|enter your (?:password|username)|forgot your password)/i;

function looksChallenge(status, text, title) {
  if (WALL_STATUSES.has(status)) return true;
  const hay = ((title || '') + '\n' + String(text || '').slice(0, 2500)).toLowerCase();
  if (!hay.trim()) return false;
  return CHALLENGE_MARKERS.some((mk) => hay.includes(mk)) && String(text || '').length < 4000;
}

// looksLogin: the WHOLE page is a sign-in gate, not a content page that merely links to a client login.
// Guarded by content dominance (thin visible text OR a password field on a short page), never byte count
// alone (caution.md C-031).
function looksLogin(html, text) {
  const t = String(text || '');
  if (!LOGIN_MARKERS.test((t + ' ' + extractTitle(html)))) return false;
  const hasPasswordField = /<input\b[^>]*type\s*=\s*["']password["']/i.test(String(html));
  if (t.length < 600) return true;
  return hasPasswordField && t.length < 1500;
}

// looksSpaShell: HTTP 200, an HTML document, but near-zero visible text (C-032, royalparkpartners.com).
function looksSpaShell(html, text) {
  if (String(text || '').length >= 200) return false;
  const body = String(html || '');
  if (!/<html[\s>]/i.test(body) && !/<div/i.test(body)) return false;
  return /<div[^>]*id\s*=\s*["'](root|app|__next|___gatsby)["']/i.test(body) || /<script/i.test(body);
}

// pageContentClass(status, html) -> 'content' | 'challenge' | 'login' | 'error' | 'empty'. Only 'content'
// enters the corpus and counts toward reachability; every other class is honestly withheld.
function pageContentClass(status, html) {
  const st = Number(status) || 0;
  if (st >= 500 || st === 404 || st === 410) return 'error';
  const text = stripHtml(html);
  if (looksChallenge(st, text, extractTitle(html))) return 'challenge';
  if (looksLogin(html, text)) return 'login';
  if (looksSpaShell(html, text)) return 'empty';
  if (text.length < 20) return 'empty';
  return 'content';
}

module.exports = {
  decodeEntities, stripHtml, extractTitle, extractOgSiteName, extractJsonLd,
  extractFooterText, extractHrefs, buildPage, pageContentClass,
};

'use strict';
/**
 * pool.js - the E-236 parallel primitive and the Rule 9 hard-deadline wrapper.
 *
 * E-236 restored a 43s crawl to 6.9s with identical accuracy by removing the IDLING, not the work: I/O-
 * bound page fetches run in a bounded-concurrency pool with a wall-clock deadline that is a CAP (it stops
 * STARTING new work past the deadline), never a floor (Constitution Rule 8 - no Math.max, no minimum wait).
 * The pool width comes from the caller; nothing here widens or floors it.
 *
 * Rule 9: every external step is wrapped in a hard Promise.race deadline, so a slow dependency degrades
 * the crawl (a null slot) and never hangs it (the 752s stuck-Chromium class). Timers are INJECTABLE so
 * node:test drives this deterministically with no real wall-clock wait.
 */

// withDeadline(factory, ms, timers) -> a promise that settles with factory()'s value, or REJECTS once
// `ms` elapses, whichever is first. timers defaults to the globals; a test injects a fake pair. The
// timer is always cleared so a resolved factory never leaves a dangling handle keeping the process alive.
function withDeadline(factory, ms, timers) {
  const T = timers || { setTimeout, clearTimeout };
  let timer = null;
  const deadline = new Promise((_resolve, reject) => {
    timer = T.setTimeout(() => reject(new Error('deadline exceeded after ' + ms + 'ms')), ms);
    if (timer && typeof timer.unref === 'function') timer.unref();
  });
  return Promise.race([Promise.resolve().then(factory), deadline])
    .finally(() => { if (timer) T.clearTimeout(timer); });
}

// runPool(items, width, deadlineMs, fn, now) -> results aligned to `items` (null where a fetch failed or
// the wall-clock deadline was reached before that item STARTED). `now` is injectable (defaults to
// Date.now) so a test can prove the deadline is a cap: advance the clock past deadlineMs and the pool
// stops starting work, leaving the un-started tail null - it never blocks and never floors.
async function runPool(items, width, deadlineMs, fn, now) {
  const clock = typeof now === 'function' ? now : Date.now;
  const out = new Array(items.length);
  let idx = 0;
  const start = clock();
  async function worker() {
    for (;;) {
      const i = idx++;
      if (i >= items.length) return;
      if (clock() - start > deadlineMs) { out[i] = null; continue; } // CAP: never START past the deadline
      try { out[i] = await fn(items[i], i); }
      catch (e) { out[i] = null; /* FAIL-OPEN: one page's failure degrades to a null slot and the crawl continues (E-236 tolerance); the null is visible to the caller's telemetry, not swallowed silently. */ }
    }
  }
  const lanes = items.length === 0 ? 0 : Math.min(width, items.length);
  await Promise.all(Array.from({ length: lanes }, worker));
  return out;
}

module.exports = { withDeadline, runPool };

'use strict';
/**
 * discover.js - link + sitemap discovery and the E-236 Tier-1-first ordering.
 *
 * Two properties this file exists to preserve:
 *  - QUERY-STRING URLs are crawled (caution.md C-027): CMS policy pages live at /privacy?page_id=42, so
 *    link discovery keeps '?' (only the fragment is dropped). isNonCrawlable in the safe-fetch door drops
 *    mailto/tel/js schemes; a query string is never dropped.
 *  - TIER-1 legal pages (privacy, cookies, terms, complaints) are ordered ahead of any commercial page
 *    and BEFORE the page cap applies (caution.md C-026): orderCandidates ranks by tier, THEN slices to the
 *    cap, so a Tier-1 page discovered LAST still survives a cap smaller than the candidate count.
 *
 * Sitemap discovery fans out in PARALLEL (E-236): the robots.txt sitemap roots race together and each
 * root's child sitemaps are fetched together; the identical URL set is produced with the idling removed.
 * The XML fetch is INJECTED (fetchXml) so this module is pure/offline and node:test drives it with mocks.
 * Host identity is decided ONLY through the tools/lib/safe-fetch.js parsed-host door.
 */

const safeFetch = require('../../tools/lib/safe-fetch.js');
const { extractHrefs } = require('./extract.js');

// Guessed policy-path backstop (privacy/cookie/terms FIRST) for sites whose links/sitemap miss them.
const POLICY_PATHS = [
  '/privacy', '/privacy-policy', '/cookies', '/cookie-policy', '/terms', '/terms-and-conditions',
  '/legal', '/complaints', '/accessibility', '/data-protection',
];

const TIER1_RX = /privacy|cookie|terms|legal|gdpr|data[-_ ]protection|accessibility|complaint|modern[-_ ]slavery|disclaimer|imprint|disclosure|safeguard|regulat|compliance|confidentialit|datenschutz|rgpd/i;
const TIER2_RX = /about|contact|service|pricing|prices|fees|returns|refund|shipping|delivery|team|locations|offices|sector/i;
const BLOG_RX = /\/blog|\/news|\/insights|\/press|\/article|\/resources|\/stories|\/updates|\/knowledge|\/20\d\d\//i;

// classifyTier(url) -> the crawl priority tier of a URL by PATH (not host): 'tier1' policy/legal,
// 'tier2' commercial, 'blog' editorial, 'other'. Tier-1 wins even if the URL also matches a lower tier.
function classifyTier(url) {
  const u = String(url || '');
  if (TIER1_RX.test(u)) return 'tier1';
  if (TIER2_RX.test(u)) return 'tier2';
  if (BLOG_RX.test(u)) return 'blog';
  return 'other';
}

const TIER_RANK = { tier1: 1, tier2: 2, blog: 3, other: 4 };
function normaliseUrl(u) { return String(u).split('#')[0].replace(/\/$/, '').toLowerCase(); }

// discoverLinks(html, base, accepted) -> the same-registrable-site hrefs on a page, resolved absolute,
// query strings kept (C-027), fragments/mailto/tel/js dropped, deduped in discovery order.
function discoverLinks(html, base, accepted) {
  const out = [];
  const seen = new Set();
  for (const href of extractHrefs(html)) {
    if (safeFetch.isNonCrawlable(href)) continue;
    let abs;
    try { abs = new URL(href, base).toString(); } catch (e) { continue; /* FAIL-OPEN: an unparseable href is not a crawl target; skipping it hides nothing (the URL simply is not a link). */ }
    if (!safeFetch.sameRegistrableSite(abs, accepted)) continue;
    const clean = abs.split('#')[0];
    const key = normaliseUrl(clean);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(clean);
  }
  return out;
}

// parseSitemapLocs(xml) -> { pageUrls, childSitemaps } from a <urlset>/<sitemapindex> body.
function parseSitemapLocs(xml) {
  const locs = (String(xml || '').match(/<loc>\s*([^<\s]+)\s*<\/loc>/gi) || [])
    .map((x) => x.replace(/<\/?loc>/gi, '').trim());
  return {
    childSitemaps: locs.filter((u) => /sitemap.*\.xml/i.test(u)).slice(0, 8),
    pageUrls: locs.filter((u) => !/\.xml/i.test(u)),
  };
}

// sitemapRoots(domain, robotsBody) -> the sitemap roots to try: robots.txt Sitemap: directives first
// (authoritative), then the conventional roots.
function sitemapRoots(domain, robotsBody) {
  const roots = [];
  for (const m of String(robotsBody || '').matchAll(/(?:^|\n)\s*sitemap:\s*(\S+)/gi)) roots.push(m[1].trim());
  roots.push('https://' + domain + '/sitemap.xml', 'https://' + domain + '/sitemap_index.xml', 'https://' + domain + '/sitemap-index.xml');
  return roots;
}

// collectSitemapPages(body, accepted, fetchXml) -> same-site page URLs from one root body, following its
// child sitemaps in PARALLEL (E-236). Returns [] when the body yields no same-site pages.
async function collectSitemapPages(body, accepted, fetchXml) {
  const { pageUrls, childSitemaps } = parseSitemapLocs(body);
  const urls = pageUrls.filter((u) => safeFetch.sameRegistrableSite(u, accepted));
  const childBodies = await Promise.all(childSitemaps.map((cs) => fetchXml(cs).catch(() => '')));
  for (const cb of childBodies) {
    for (const u of parseSitemapLocs(cb).pageUrls) if (safeFetch.sameRegistrableSite(u, accepted)) urls.push(u);
  }
  return urls;
}

// discoverSitemap(domain, accepted, fetchXml) -> same-site page URLs from the sitemap. Roots race in
// PARALLEL; the first root that yields same-site pages wins (identical set, no sequential idling).
async function discoverSitemap(domain, accepted, fetchXml) {
  const robots = await fetchXml('https://' + domain + '/robots.txt').catch(() => '');
  const roots = sitemapRoots(domain, robots);
  const bodies = await Promise.all(roots.map((r) => fetchXml(r).catch(() => '')));
  for (const body of bodies) {
    if (!body) continue;
    const urls = await collectSitemapPages(body, accepted, fetchXml);
    if (urls.length) return urls;
  }
  return [];
}

// guessedPaths(accepted) -> the policy-path backstop across every accepted registrable host.
function guessedPaths(accepted) {
  const out = [];
  for (const reg of accepted) for (const p of POLICY_PATHS) out.push('https://' + reg + p);
  return out;
}

// orderCandidates(homeUrl, discovered, accepted, maxPages) -> the deduped, same-site fetch list ordered
// TIER-1-FIRST and THEN capped (C-026): the homepage leads, then Tier-1 (legal), Tier-2 (commercial),
// blog, other; a stable sort preserves discovery order within a tier; the cap is applied LAST so Tier-1
// survives even when it was discovered last and the cap is smaller than the candidate count.
function orderCandidates(homeUrl, discovered, accepted, maxPages) {
  const homeKey = normaliseUrl(homeUrl);
  const pool = [homeUrl, ...guessedPaths(accepted), ...(discovered || [])];
  const seen = new Set();
  const ranked = [];
  for (const u of pool) {
    if (!safeFetch.sameRegistrableSite(u, accepted)) continue;
    const key = normaliseUrl(u);
    if (seen.has(key)) continue;
    seen.add(key);
    ranked.push({ url: u, rank: key === homeKey ? 0 : TIER_RANK[classifyTier(u)] });
  }
  ranked.sort((a, b) => a.rank - b.rank); // stable in Node: ties keep discovery order
  const capped = ranked.slice(0, maxPages).map((r) => r.url);
  return capped;
}

module.exports = {
  POLICY_PATHS, classifyTier, discoverLinks, discoverSitemap, orderCandidates,
  parseSitemapLocs, guessedPaths, normaliseUrl,
};

'use strict';
/**
 * coverage-contract.js - coverage as BLOCKING DATA, not reporting theatre (caution.md C-029).
 *
 * The reconciliation gate used to check "was the site reachable", not "did we read the page the rule
 * needs", so absence rules fired on pages nobody read. Here every catalogue rule declares the page-class
 * its website obligations need, and coverageFor() answers per rule: `covered` (that class was crawled) or
 * `screened` (it was not; NEVER a breach input). Wave-2 treats `screened` as a HARD BLOCK: no screened
 * rule may become a breach.
 *
 * classify() (caution.md C-044) matches PATH SEGMENTS with anchored tokens, never loose substrings, so
 * /feedback does not credit 'fees', /cost-of-living does not credit 'pricing', /returning-customers does
 * not credit 'returns'. Pure and deterministic: no network, no clock, no env.
 *
 * The absence-demotion interlock (caution.md C-024/C-033): a rule whose evidence would be an ABSENCE claim
 * is demoted to `screened` (needs-review) when the corpus was truncated, and any page-class that exists
 * only inside an unparsed document (evidence/documents 'no-parser') is treated as NOT covered.
 */

const BASE_REQUIRED = ['homepage', 'privacy'];
const SECTOR_REQUIRED = {
  'law-firms': ['complaints', 'pricing'], barristers: ['complaints'], finance: ['terms'],
  insurance: ['terms'], ecommerce: ['terms', 'returns'], retail: ['terms'],
  healthcare: ['privacy'], 'real-estate': ['fees'],
};

function requiredClasses(sector) {
  const extra = SECTOR_REQUIRED[String(sector || '').toLowerCase()] || [];
  return [...new Set([...BASE_REQUIRED, ...extra])];
}

// classify(page) -> the page-class of a fetched URL by PATH SEGMENT with anchored tokens (C-044). Accepts
// a page object ({url}|{type}) or a bare string.
function classify(page) {
  const raw = String((page && (page.url || page.type || page)) || '').toLowerCase();
  const path = raw.replace(/^https?:\/\/[^/]+/, '');
  const seg = '/' + path.replace(/[?#].*$/, '').replace(/^\/+/, ''); // normalised path, leading slash
  const has = (re) => re.test(seg);
  if (has(/\b(privacy|data[-_ ]?protection|gdpr|cookie)\b/)) return 'privacy';
  if (has(/\b(complaints?|ombudsman)\b/)) return 'complaints';
  if (has(/\bfees?\b/)) return 'fees';
  if (has(/\b(pricing|prices?|tariff|cost[-_ ]?(of[-_ ]?service|guide|schedule)?|charges)\b/) && !/\bcost[-_ ]?of[-_ ]?living\b/.test(seg)) return 'pricing';
  if (has(/\b(terms|t-and-c|conditions)\b/)) return 'terms';
  if (has(/\b(returns?|refunds?)\b/)) return 'returns';
  if (/^\/?$/.test(seg) || has(/\b(home|index)\b/)) return 'homepage';
  return 'other';
}

// fetchedClassSet(crawledPages) -> the Set of page-classes present in the crawl. The homepage counts as
// present whenever ANY page was read (you always land somewhere), and 'any' is the general-corpus class.
function fetchedClassSet(crawledPages) {
  const set = new Set((crawledPages || []).map(classify));
  if ((crawledPages || []).length) { set.add('homepage'); set.add('any'); }
  return set;
}

// computeCoverage(crawledPages, sector, opts) -> site-level tri-state: 'assessable' (enough required
// classes) or 'screened' (too little coverage -> not-assessed, never a breach on unread content).
function computeCoverage(crawledPages, sector, opts = {}) {
  const required = requiredClasses(sector);
  const fetched = fetchedClassSet(crawledPages);
  const missing = required.filter((c) => !fetched.has(c));
  const ratio = required.length ? (required.length - missing.length) / required.length : 0;
  const threshold = typeof opts.threshold === 'number' ? opts.threshold : 0.5;
  const reachable = (crawledPages || []).length > 0;
  const render_class = (!reachable || ratio < threshold) ? 'screened' : 'assessable';
  return { required, fetched_classes: [...fetched].sort(), missing, ratio: Math.round(ratio * 100) / 100, render_class, reachable };
}

// pageClassForObligation(obligation) -> the crawl page-class an on-page presence/absence duty needs,
// derived from anchored tokens in the duty + element text; 'any' when the duty is a general on-page
// requirement (assessable on the homepage/footer). register/behavioural duties return null (their
// evidence comes from the registers/browser lanes, not the crawl).
function pageClassForObligation(obligation) {
  const et = obligation && obligation.evidence_type;
  if (et !== 'presence' && et !== 'absence') return null;
  const text = ((obligation.duty || '') + ' ' + (obligation.elements || []).join(' ')).toLowerCase();
  if (/\b(privacy|data protection|gdpr|cookie|personal data)\b/.test(text)) return 'privacy';
  if (/\b(complaint|ombudsman|redress)\b/.test(text)) return 'complaints';
  if (/\bfees?\b/.test(text)) return 'fees';
  if (/\b(pricing|price|tariff|charges|cost of service)\b/.test(text)) return 'pricing';
  if (/\b(terms|conditions)\b/.test(text)) return 'terms';
  if (/\b(returns?|refunds?)\b/.test(text)) return 'returns';
  return 'any';
}

// ruleNeeds(rule) -> { needs: [pageClass...], laneOnly: bool, hasAbsence: bool }. laneOnly means the rule
// has NO on-page text obligation (its evidence is register/behavioural), so the crawl does not gate it.
function ruleNeeds(rule) {
  const obligations = (rule && rule.website_obligations) || [];
  const needs = new Set();
  let hasAbsence = false;
  for (const o of obligations) {
    const cls = pageClassForObligation(o);
    if (cls) needs.add(cls);
    if (o && o.evidence_type === 'absence') hasAbsence = true;
  }
  return { needs: [...needs], laneOnly: needs.size === 0, hasAbsence };
}

// judgeRule(rule, fetched, ctx) -> the per-rule coverage verdict. `ctx` carries the interlock inputs:
// truncated (C-024) and unparsedClasses (C-033).
function judgeRule(rule, fetched, ctx) {
  const { needs, laneOnly, hasAbsence } = ruleNeeds(rule);
  if (laneOnly) return { id: rule.id, state: 'covered', needs: [], missing: [], reason: 'non-crawl-evidence (register/behavioural lane)' };
  const missing = needs.filter((c) => c !== 'any' && !fetched.has(c));
  const unparsed = needs.filter((c) => ctx.unparsedClasses.has(c));
  const truncatedAbsence = ctx.truncated && hasAbsence;
  const reasons = [];
  if (missing.length) reasons.push('missing page-class: ' + missing.join(', '));
  if (unparsed.length) reasons.push('page-class only in an unparsed document (C-033): ' + unparsed.join(', '));
  if (truncatedAbsence) reasons.push('absence claim on a truncated corpus demoted (C-024)');
  const covered = reasons.length === 0;
  return { id: rule.id, state: covered ? 'covered' : 'screened', needs, missing, reason: covered ? 'all needed page-classes crawled' : reasons.join('; ') };
}

// coverageFor(rules, crawledPages, opts) -> { rules:[{id,state,needs,missing,reason}], summary } where
// state is covered|screened per rule. `opts.truncated` and `opts.unparsedClasses` drive the interlock.
function coverageFor(rules, crawledPages, opts = {}) {
  const fetched = fetchedClassSet(crawledPages);
  const ctx = {
    truncated: Boolean(opts.truncated),
    unparsedClasses: opts.unparsedClasses instanceof Set ? opts.unparsedClasses : new Set(opts.unparsedClasses || []),
  };
  const out = (rules || []).map((r) => judgeRule(r, fetched, ctx));
  const screened = out.filter((r) => r.state === 'screened').length;
  return { rules: out, summary: { total: out.length, covered: out.length - screened, screened } };
}

// isScreened(coverage, ruleId) -> true when wave-2 must NOT emit a breach for this rule (hard block).
function isScreened(coverage, ruleId) {
  const r = coverage && coverage.rules && coverage.rules.find((x) => x.id === ruleId);
  return Boolean(r) && r.state === 'screened';
}

// applyCoverage(findings, coverage) -> drop breach ('miss') findings when the SITE coverage is screened.
function applyCoverage(findings, coverage) {
  if (!coverage || coverage.render_class === 'assessable') return findings || [];
  return (findings || []).filter((f) => f && f.status !== 'miss');
}

module.exports = {
  BASE_REQUIRED, SECTOR_REQUIRED, requiredClasses, classify, computeCoverage,
  coverageFor, isScreened, applyCoverage, pageClassForObligation, ruleNeeds,
};

